hooks.command:
echo "$CLAUDE_TOOL_INPUT" | python3 -c "
import sys, json, subprocess, os
data = json.load(sys.stdin)
path = data.get('file_path', '') or data.get('path', '')
if 'types/index.ts' in path or 'services/appKnowledge.ts' in path:
    script = os.path.join(os.path.dirname(path.split('types')[0].split('services')[0].rstrip('/')), 'scripts/update-site.js')
    # Găsim root-ul proiectului
    parts = path.replace('\\\\', '/').split('/')
    for i, p in enumerate(parts):
        if p in ('types', 'services'):
            root = '/'.join(parts[:i])
            script_path = root + '/scripts/update-site.js'
            if os.path.exists(script_path):
                result = subprocess.run(['node', script_path], capture_output=True, text=True, cwd=root)
                if result.returncode == 0:
                    print('[AUTO-SYNC] docs/ actualizat cu succes')
                else:
                    print(f'[AUTO-SYNC] Eroare update-site: {result.stderr[:200]}')
            break
"
